	(1, 'HTUY_W1_10_OVERVIEW', 'how_to_use_yoga', NULL, 'rotation_protocol', 1, 10, NULL, '{"weeks": "1-10", "source": "How to Use Yoga", "objective": "Foundational establishment and systemic revision", "ui_requirement": {"logic": "User marks preferred sequences from previous weeks to populate revision buffers.", "feature": "Do Again tracker"}}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(2, 'HTUY_W5_REVISION', 'how_to_use_yoga', NULL, 'mixing_logic', 5, 5, NULL, '{"logic": ["Alternate between Dynamic (Standing/Vinyasa-based) and Resting (Support-based/Pranayama) programs.", "Calibration: Ensure a 1:1 ratio of Active to Restorative sequences across the 7-day period."], "source": "How to Use Yoga", "week_index": 5, "input_source": ["Week 3", "Week 4"]}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(3, 'HTUY_W10_CONSOLIDATION', 'how_to_use_yoga', NULL, 'consolidation_protocol', 10, 10, 'confident', '{"logic": ["Selection: User-driven concentration on challenging or preferred modules.", "Constraint: Reserve Buffer Required."], "source": "How to Use Yoga", "ui_alert": {"message": "RESERVE ALERT: You must have 7 sequences tagged as ''Do Again'' or ''Concentrate'' to fulfill Week 10 revision requirements.", "trigger": "Start of Week 9"}, "week_index": 10, "input_source": ["Week 6", "Week 7", "Week 8", "Week 9"]}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(4, 'YTIW_C1_ROTATION', 'yoga_the_iyengar_way', 'Course 1', 'rotation_protocol', NULL, NULL, 'confident', '{"logic": [{"week_n": "Lesson [n] + Lesson [n+1]"}, {"sequence": "1&2, 2&3, 3&4, 4&5..."}], "source": "Yoga The Iyengar Way", "pattern": "sliding_window_pairs", "frequency": "weekly", "source_course": "Course 1", "repetition_protocol": [{"total_cycles": 2}, {"action": "Repeat entire progression after final lesson pair is reached"}]}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(5, 'YTIW_C2_OVERVIEW', 'yoga_the_iyengar_way', 'Course 2', 'course_structure', NULL, NULL, NULL, '{"notes": ["Weekly rotation follows the A-D group sequence."], "source": "Yoga The Iyengar Way", "daily_focus": "Single posture depth", "lesson_count": 36, "lesson_groups": {"A": "Standing", "B": "Sitting", "C": "Miscellaneous or Backbends", "D": "Relaxation and Pranayama"}, "source_course": "Course 2", "duration_suggested": "18 months"}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(6, 'YTIW_C2_ROTATION_M1', 'yoga_the_iyengar_way', 'Course 2', 'monthly_rotation', NULL, NULL, 'confident', '{"month": 1, "source": "Yoga The Iyengar Way", "pattern": {"week_1": ["1A", "2A"], "week_2": ["1B", "2B"], "week_3": ["1C", "2C"], "week_4": ["1D", "2D"]}, "repeat_for": "Full month", "source_course": "Course 2"}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(7, 'YTIW_C2_ROTATION_M3', 'yoga_the_iyengar_way', 'Course 2', 'monthly_rotation', NULL, NULL, 'confident', '{"month": 3, "notes": "Alternate current lessons (2&3) while repeating baseline (1)", "source": "Yoga The Iyengar Way", "pattern": {"week_1": ["2A", "3A", "1A"], "week_2": ["2B", "3B", "1B"], "week_3": ["2C", "3C", "1C"], "week_4": ["2D", "3D", "1D"]}, "source_course": "Course 2"}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(8, 'YTIW_C2_CONSOLIDATION_LOGIC', 'yoga_the_iyengar_way', 'Course 2', 'consolidation', NULL, NULL, 'confident', '{"action": "Repeat previous 3 months of lessons", "source": "Yoga The Iyengar Way", "intervals": [3, 6, 9], "final_phase": {"focus": "All lessons 1-9 A-D", "trigger": "Completion of Lesson 9", "duration": "6 months"}, "source_course": "Course 2"}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(9, 'YTIW_C3_OVERVIEW', 'yoga_the_iyengar_way', 'Course 3', 'course_structure', NULL, NULL, NULL, '{"notes": ["Focus heavily on backbends in this stage.", "Requires high physical stamina and established hold times."], "source": "Yoga The Iyengar Way", "lesson_count": 16, "source_course": "Course 3", "alternation_logic": "Alternate with Course II"}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(10, 'YTIW_C3_PREREQUISITES', 'yoga_the_iyengar_way', 'Course 3', 'technical_proficiency', NULL, NULL, 'confident', '{"source": "Yoga The Iyengar Way", "mastery_list": ["132", "130", "172", {"074_TRANSITION": "Dropping back from Sirsasana"}], "source_course": "Course 3", "required_holds": {"074": 900, "087": 1200, "091": 600}, "flexibility_markers": ["045", {"FORWARD_BEND": "Head to shins with straight legs"}, {"TWIST": "Binding/Catching hands"}]}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(11, 'YTIW_C3_CONSOLIDATION_LOGIC', 'yoga_the_iyengar_way', 'Course 3', 'rotation_protocol', NULL, NULL, 'confident', '{"source": "Yoga The Iyengar Way", "phase_1": {"action": "Repeat all lessons", "trigger": "Completion of 4A-D"}, "phase_2": {"pattern": "Overlapping pairs (1&2, 2&3, etc) across A-D groups", "duration": "4 months"}, "phase_3": {"action": "Total consolidation of all previous lessons", "duration": "3 months"}, "source_course": "Course 3"}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(12, 'YTIW_C4_OVERVIEW', 'yoga_the_iyengar_way', 'Course 4', 'course_structure', NULL, NULL, NULL, '{"notes": ["Base sequences are extensible; additional asanas from the database are permitted.", "Pranayama (203-217) follows Savasana (200) or remains independent."], "source": "Yoga The Iyengar Way", "lesson_count": 6, "source_course": "Course 4", "daily_protocol": "Different emphasis each day"}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(13, 'YTIW_C4_PRANAYAMA_INTEGRATION', 'yoga_the_iyengar_way', 'Course 4', 'sequencing_logic', NULL, NULL, 'confident', '{"source": "Yoga The Iyengar Way", "source_course": "Course 4", "sequence_order": ["asana_practice", "200", "pranayama_practice"], "optional_standalone": true}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(14, 'LOY_C1_PROGRESSION', 'light_on_yoga', 'Course 1', 'rotation_protocol', 1, 18, NULL, '{"source": "Light on Yoga", "source_course": "Course 1", "progression_milestones": {"week_7": {"logic": "Increase length of stay (Flow calibration) in all asanas.", "action": "CONSOLIDATE"}, "week_13": {"logic": "Repeat and steady practice. Extension permitted if mastery is pending.", "action": "STABILIZE"}, "week_18": {"logic": "If Standing Poses (001-015) are mastered, transition to alternate days or 2x weekly.", "action": "DYNAMIC_SCHEDULING"}, "weeks_1_6": {"logic": "Execute standard weekly sequence blocks.", "action": "FOLLOW_SEQUENCES"}}}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(15, 'LOY_C1_3DAY_CYCLE', 'light_on_yoga', 'Course 1', 'rotation_protocol', NULL, NULL, NULL, '{"source": "Light on Yoga", "pattern": "3-day rolling cycle", "sunday_protocol": {"alternative": "Rest", "sequence_id": 3}}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(16, 'LOY_C1_SURYA_NAMASKAR', 'light_on_yoga', 'Course 1', 'repetition_logic', NULL, NULL, NULL, '{"focus": ["Arms", "Chest"], "base_reps": 6, "increment": "According to capacity", "source_id": 5, "target_asana": "140"}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(17, 'LOY_C1_IMPORTANT_ASANAS_113', 'light_on_yoga', 'Course 1', 'mastery_gate', NULL, NULL, NULL, '{"notes": "Mastery of this specific list yields proficiency in all other Course 1 asanas.", "source_id": "113", "priority_asanas": ["003", "004", "005", "006", "007", "009", "010", "012", "013", "016", "020", "025", "027", "033", "034", "036", "039", "040", "044", "045", "051", "059", "067", "074", "087", "091", "114", "116", "200"]}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(18, 'LOY_C2_PROGRESSION', 'light_on_yoga', 'Course 2', 'rotation_protocol', 31, 78, NULL, '{"source": "Light on Yoga", "source_course": "Course 2", "progression_milestones": {"weeks_31_39": {"logic": "Begin Course 2 sequences as per appendix.", "action": "INITIAL_INTEGRATION"}, "weeks_40_44": {"logic": "Consolidate all positions; prioritize asanas omitted in Course 1.", "action": "GAP_CONSOLIDATION"}, "weeks_51_54": {"logic": ["Execute all Important Asanas from Course 1 (ID 113).", "Perfect new positions in Course 2.", "Timing: Adjust hold durations to user convenience/stamina."], "action": "HYBRID_MASTERY"}, "weeks_74_78": {"logic": "Cyclical repetition of all asanas from Course 1 and Course 2.", "action": "FULL_SYSTEM_REPETITION"}}}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(19, 'LOY_C2_SUMMARY_WEEK', 'light_on_yoga', 'Course 2', 'weekly_summary', NULL, NULL, NULL, '{"day_7": {"alternative": "Rest", "sequence_id": 3}, "day_1_6": "Execute summary sequences ID 136 through 141.", "source_id": "136-141"}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(20, 'LOY_C2_IMPORTANT_ASANAS_128', 'light_on_yoga', 'Course 2', 'mastery_gate', NULL, NULL, NULL, '{"notes": "Significant focus on Sirsasana and Sarvangasana variations.", "source_id": "128"}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(21, 'LOY_C3_PROGRESSION', 'light_on_yoga', 'Course 3', 'rotation_protocol', 79, 180, NULL, '{"source": "Light on Yoga", "source_course": "Course 3", "progression_milestones": {"week_79": {"action": "START_COURSE_3"}, "weeks_91_94": {"logic": "Perform Important Asanas (C1 & C2) + all added Course 3 asanas.", "action": "CUMULATIVE_REVIEW"}, "weeks_101_108": {"logic": "Concentrate on 177 (Viparita Dandasana) from 074 (Sirsasana) with the ''swing back'' to 074.", "action": "TRANSITION_FOCUS"}, "weeks_109_125": {"reps": 15, "logic": "Daily at a stretch. If mastery is not achieved, extend period.", "action": "INTENSIVE_DRILL", "target": "173"}, "weeks_156_160": {"logic": "Repeat Important Asanas (C1 & C2) + Course 3 current set.", "action": "IMPORTANT_ASANA_LOOP"}, "weeks_176_180": {"logic": "Attempt daily irrespective of failure; continue until mastered.", "action": "MASTERY_GATE", "target_asana": "122"}}}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(22, 'LOY_C3_BACKBEND_PROTOCOL', 'light_on_yoga', 'Course 3', 'repetition_logic', 131, 136, NULL, '{"notes": "If stiffness occurs, extend duration; priority is improving back-bending before proceeding.", "weeks": "131-136", "drill_list": [{"id": "154", "reps": 15}, {"id": "146"}, {"id": "173", "reps": 15}, {"id": "177"}, {"id": "175"}]}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(23, 'LOY_C3_CIRCADIAN_LOGIC', 'light_on_yoga', 'Course 3', 'session_splitting', NULL, NULL, NULL, '{"condition": "Applied if Pranayama becomes too strenuous to perform with backbends.", "am_session": "Difficult Asanas + Pranayama", "pm_session": "Cycles of 074 (Sirsasana) and 087 (Sarvangasana)"}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(24, 'LOY_C3_SUMMARY_WEEK', 'light_on_yoga', 'Course 3', 'weekly_summary', NULL, NULL, NULL, '{"day_7": {"alternative": "Rest", "sequence_id": 3}, "duration": "7 days", "source_id": "142-148"}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(25, 'LOY_C3_MARATHON_LOGIC', 'light_on_yoga', 'Course 3', 'rotation_protocol', 226, 250, NULL, '{"weeks": "226-250", "re_entry": [{"target_id": "172"}, {"sequence": ["198", "199"]}, {"return_to": "Week 200 course from ID 169 onwards"}], "entry_point": "Follow Week 200 course up to ID 184", "intensive_block": [["185", "186", "187", "188"], ["195", "196", "197"]]}', '2026-05-03 05:14:51.471707+00', '2026-05-03 05:14:51.471707+00', NULL, NULL, NULL, NULL),
	(26, 'LOP_OVERVIEW', 'light_on_pranayama', NULL, 'course_structure', NULL, NULL, 'confident', '{"logic": ["Pranayama is divided into five progressive groups for daily practice.", "The time required to gain control varies by practitioner dedication and practice.", "Courses are divided first for easy reference, then developed week by week."], "course_count": 5, "course_groups": ["Preparatory", "Primary", "Intermediate", "Advanced", "Highly Intense"]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', NULL, 'pranayama_course_rules', 'Overview of the five-course pranayama structure.'),
	(27, 'LOP_MINOR_PRANAYAMA_GUIDANCE', 'light_on_pranayama', NULL, 'auxiliary_practice_guidance', NULL, NULL, 'confident', '{"minor_pranayamas": {"sitali_sitakari": {"usage": "May be done with or without digital control and with or without internal/external retention.", "timing": "Useful in hot weather, before sunrise or after sunset, or when overheated.", "duration": "A few minutes once in a while."}, "bhramari_murchha": {"usage": "May be practised merely to learn the method.", "rationale": "Their effects are covered by the major pranayamas."}, "kapalabhati_bhastrika": {"usage": "May be added for a few minutes to cleanse the nostrils and refresh the brain.", "constraint": "Adjust stages according to body and nostril condition."}}}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', NULL, 'pranayama_course_rules', 'Guidance for minor or auxiliary pranayamas.'),
	(28, 'LOP_RETENTION_AND_RATIO_GUIDANCE', 'light_on_pranayama', NULL, 'breath_timing_guidance', NULL, NULL, 'confident', '{"logic": ["Limited time is prescribed for retentions, not for inhalations and exhalations.", "On some days the practitioner may concentrate on lengthening inhalation and exhalation.", "On other days the focus may be internal retention or external retention.", "Vrtti pranayama ratios may be attempted only after sufficient control has been acquired."], "caution": ["Vrtti ratios are attempted at the practitioner''s own risk."]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', NULL, 'pranayama_course_rules', 'Guidance on retentions, inhalations/exhalations, and vrtti ratios.'),
	(29, 'LOP_C1_OVERVIEW', 'light_on_pranayama', 'Course 1', 'course_structure', 1, 25, 'confident', '{"important_stages": {"ujjayi": ["II", "III", "IV", "VI", "VII"], "viloma": ["I"]}, "included_pranayamas": ["Ujjayi", "Viloma"]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Preparatory Course', 'pranayama_course_rules', 'Course 1 overview and important stages.'),
	(30, 'LOP_C1_PROGRESSION', 'light_on_pranayama', 'Course 1', 'progression_protocol', 1, 25, 'confident', '{"weeks": {"1-25": {"logic": ["Practise progressive Ujjayi and Viloma stages according to the saved course sequences.", "Repeat and consolidate before moving to Course 2.", "Become accustomed to the series before increasing complexity."]}}, "consolidation_logic": ["Repeat and consolidate the preparatory series.", "Important stages from Course 1 should be retained for future courses."]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Preparatory Course', 'pranayama_course_rules', 'Course 1 progression and consolidation logic.'),
	(31, 'LOP_C2_OVERVIEW', 'light_on_pranayama', 'Course 2', 'course_structure', 26, 62, 'confident', '{"important_stages": {"ujjayi": ["X"], "viloma": ["III"], "anuloma": ["Ib"], "pratiloma": ["Ib"], "surya_bhedana": ["I"], "chandra_bhedana": ["I"]}, "included_pranayamas": ["Ujjayi", "Viloma", "Anuloma", "Pratiloma", "Surya Bhedana", "Chandra Bhedana"]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Primary Course', 'pranayama_course_rules', 'Course 2 overview and important stages.'),
	(32, 'LOP_C2_CONSOLIDATION', 'light_on_pranayama', 'Course 2', 'consolidation_protocol', 47, 62, 'confident', '{"weeks": {"47-50": {"logic": ["Repeat important stages from Course 1.", "Practise what is possible from Course 2 according to available time."], "action": "Repeat and consolidate."}, "59-62": {"logic": ["Adjust the practice according to the time at the practitioner''s disposal."], "action": "Repeat Course 2 and consolidate."}}}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Primary Course', 'pranayama_course_rules', 'Course 2 consolidation windows.'),
	(33, 'LOP_C3_OVERVIEW', 'light_on_pranayama', 'Course 3', 'course_structure', 63, 120, 'confident', '{"important_stages": {"ujjayi": ["XI"], "viloma": ["VII"], "anuloma": ["IIb"], "pratiloma": ["IIb"], "nadi_sodhana": ["II"], "surya_bhedana": ["II"], "chandra_bhedana": ["II"]}, "included_pranayamas": ["Ujjayi", "Viloma", "Anuloma", "Pratiloma", "Surya Bhedana", "Chandra Bhedana", "Nadi Sodhana"]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Intermediate Course', 'pranayama_course_rules', 'Course 3 overview and important stages.'),
	(34, 'LOP_C3_ALTERNATION_LOGIC', 'light_on_pranayama', 'Course 3', 'alternation_protocol', 63, 80, 'confident', '{"weeks": {"63-67": {"logic": ["Some listed pranayamas may be practised on one day and the others on alternate days."]}, "73-75": {"logic": ["If Anuloma is done one day, Pratiloma may be done the next day."]}, "76-80": {"logic": ["If Anuloma, Surya Bhedana, and Nadi Sodhana are done on the first day, practise the remaining items on the second day, and continue alternating."]}}}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Intermediate Course', 'pranayama_course_rules', 'Course 3 alternation logic across selected week blocks.'),
	(35, 'LOP_C3_CONSOLIDATION', 'light_on_pranayama', 'Course 3', 'consolidation_protocol', 81, 120, 'confident', '{"weeks": {"81-85": {"action": "Consolidate the practice."}, "86-90": {"action": "Practise important pranayamas from Courses 1, 2, and 3."}, "91-120": {"logic": ["Each division in Courses 1, 2, and 3 should be learned well before proceeding to the Advanced Course."], "action": "Begin practising one stage at a stretch every day."}}}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Intermediate Course', 'pranayama_course_rules', 'Course 3 consolidation and one-stage-at-a-stretch practice.'),
	(36, 'LOP_C3_WEEKLY_SCHEDULING_RULES', 'light_on_pranayama', 'Course 3', 'weekly_rotation_protocol', 91, 120, 'confident', '{"logic": ["Each principal pranayama should be represented every week.", "Do not repeat any stages in any three consecutive weeks.", "Rest on Sundays or practise simple and restful pranayama.", "If the scheduled pranayama does not feel right on a particular day, choose another from the same week."], "duration_guidance": {"main_pranayama_minutes": "20-25"}, "minor_pranayama_constraint": ["Minor pranayamas should not be practised for 20-25 minutes.", "They may be tried experimentally on the last Saturday of each month for no more than five minutes."]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Intermediate Course', 'pranayama_course_rules', 'Weekly scheduling rules for Course 3 consolidation phase.'),
	(37, 'LOP_C3_PERSONALISED_SCHEDULE_LOGIC', 'light_on_pranayama', 'Course 3', 'adaptive_scheduling', 91, 120, 'confident', '{"logic": ["After completing the given weekly examples, the practitioner may prepare their own schedule.", "Continue until all pranayamas from the first three courses have been covered.", "Then restart from the first example week.", "If unable to practise certain pranayamas for physical reasons, prepare a personal schedule using only those that can be done."]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Intermediate Course', 'pranayama_course_rules', 'Personalised scheduling after the sample weekly schedules.'),
	(38, 'LOP_C4_OVERVIEW', 'light_on_pranayama', 'Course 4', 'course_structure', 121, 170, 'confident', '{"important_stages": {"anuloma": ["IIIb"], "pratiloma": ["IIb"], "nadi_sodhana": ["IIb"], "surya_bhedana": ["III"], "chandra_bhedana": ["III"]}, "included_pranayamas": ["Ujjayi", "Viloma", "Anuloma", "Pratiloma", "Surya Bhedana", "Chandra Bhedana", "Nadi Sodhana"]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Advanced Course', 'pranayama_course_rules', 'Course 4 overview and important stages.'),
	(39, 'LOP_C4_CONSOLIDATION', 'light_on_pranayama', 'Course 4', 'consolidation_protocol', 161, 170, 'confident', '{"weeks": {"161-170": {"action": "Repeat all important pranayamas from the previous courses."}}}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Advanced Course', 'pranayama_course_rules', 'Course 4 consolidation of important pranayamas.'),
	(40, 'LOP_C5_OVERVIEW', 'light_on_pranayama', 'Course 5', 'course_structure', 171, 200, 'confident', '{"important_stages": {"nadi_sodhana": ["IVb"], "surya_bhedana": ["IV"], "chandra_bhedana": ["IV"]}, "included_pranayamas": ["Ujjayi", "Viloma", "Anuloma", "Pratiloma", "Surya Bhedana", "Chandra Bhedana", "Nadi Sodhana"]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Highly Intense Course', 'pranayama_course_rules', 'Course 5 overview and important stages.'),
	(41, 'LOP_C5_INTENSITY_WARNING', 'light_on_pranayama', 'Course 5', 'intensity_caution', 171, 200, 'confident', '{"logic": ["Course 5 is classified as highly intense.", "It should only be attempted after the preparatory, primary, intermediate, and advanced courses have been properly consolidated.", "Important stages include Surya Bhedana IV, Chandra Bhedana IV, and Nadi Sodhana IVb."]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', 'Highly Intense Course', 'pranayama_course_rules', 'Course 5 intensity warning and progression constraint.'),
	(42, 'LOP_WEEKLY_PRACTICE_PROTOCOL', 'light_on_pranayama', NULL, 'weekly_practice_template', NULL, NULL, 'confident', '{"weekly_pattern": {"friday": ["Ujjayi VII", "Nadi Sodhana IVb", "Savasana"], "monday": ["Nadi Sodhana", "Ujjayi XI", "Savasana"], "tuesday": ["Viloma V and VI", "Surya Bhedana II and III", "Savasana"], "saturday": ["Viloma VI", "Nadi Sodhana", "Savasana"], "thursday": ["Chandra Bhedana I and III", "Pratiloma IIIb", "Savasana"], "wednesday": ["Nadi Sodhana IIb", "Anuloma VIIb", "Savasana"]}, "duration_guidance": {"main_pranayama_minutes": "15-20"}, "optional_addition": {"timing": "After the main pranayama and before Savasana.", "duration": "2-3 minutes.", "pranayama": "Bhastrika", "nasal_control": "With or without blocking the nasal passages."}, "sequence_structure": ["main_pranayama_1", "main_pranayama_2", "Savasana"]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', NULL, 'pranayama_course_rules', 'Weekly practice template from Light on Pranayama.'),
	(43, 'LOP_SAVASANA_INTEGRATION', 'light_on_pranayama', NULL, 'sequencing_logic', NULL, NULL, 'confident', '{"logic": ["Savasana follows the main pranayama practice in the weekly practice template.", "Optional Bhastrika, if used, comes after the main pranayama and before Savasana."], "sequence_order": ["main_pranayama", "optional_bhastrika", "Savasana"]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', NULL, 'pranayama_course_rules', 'Savasana and optional Bhastrika integration rule.'),
	(44, 'LOP_AUTOMATION_CONSTRAINTS', 'light_on_pranayama', NULL, 'app_logic_constraint', NULL, NULL, 'interpretive_but_recommended', '{"constraints": ["Do not auto-promote the user to the next course solely based on elapsed weeks.", "Promotion requires completion/consolidation of important stages.", "Minor pranayamas should not be scheduled for long-duration daily practice.", "Allow substitution within the same week when a scheduled pranayama is unsuitable.", "Allow Sunday rest or simple restful pranayama."], "ui_requirements": [{"logic": "Track whether the important stages for each course have been practised and consolidated.", "feature": "Important Stage Completion"}, {"logic": "Permit user to swap a scheduled pranayama with another from the same week.", "feature": "Adaptive Substitute"}, {"logic": "Warn if minor pranayamas are scheduled for long durations.", "feature": "Minor Pranayama Warning"}]}', '2026-05-03 05:22:13.355712+00', '2026-05-03 05:22:13.355712+00', 'Light on Pranayama', NULL, 'pranayama_course_rules', 'Recommended app automation constraints derived from the Light on Pranayama rules.');
