INSERT INTO "public"."props" ("id", "label", "icon", "color", "audio_cue", "banner_title", "banner_html", "created_at") VALUES
	('bandage', 'Therapeutic Bandage', 'ðŸ©¹', '#d35400', 'Wearing a bandage.', 'Therapeutic Protocol: Head Bandage', 'A firmly tied bandage round the head is soothing for headaches. Wind bandage around the forehead and back of the skull. Pull firmly but not tight.<br><small><em>Eyestrain: cover eyes lightly 2-3 times at start.</em></small>', '2026-04-11 08:23:58.429201+00'),
	('block', 'Block', 'ðŸ§±', '#ff0080', 'Use a block for hand support.', 'Therapeutic Protocol: Block Support', 'Core Instruction: Perform these asanas using a block for hand support rather than resting on the floor.<br>Adjustment: Utilize varying block heights to maintain spinal alignment.<br><small><em>Benefit: This protocol focuses on freeing and stretching affected areas to improve mobility through controlled support.</em></small>', '2026-04-11 08:23:58.429201+00'),
	('blanket', 'Blanket', 'ðŸ§¶', '#2ecc71', 'Use a folded blanket for support.', 'Therapeutic Protocol: Blanket Support', 'Use a folded blanket to support the neck, hips, or knees as required. Maintain even thickness to ensure level alignment.', '2026-04-11 08:23:58.429201+00'),
	('chair', 'Chair', 'ðŸª‘', '#9b59b6', 'Using a chair for support.', 'Therapeutic Protocol: Chair Support', 'Perform the asana using a stable chair for balance or to reduce weight-bearing load on the joints.', '2026-04-11 08:23:58.429201+00'),
	('pole_or_stick', 'Pole or Stick', 'ðŸ¦¯', '#7f8c8d', 'Use a pole or stick for alignment.', 'Therapeutic Protocol: Alignment Tool', 'Hold a pole or stick to help maintain arm alignment and chest opening.', '2026-04-11 08:23:58.429201+00'),
	('ledge', 'Ledge / Wall Ledge', 'ðŸªœ', '#e67e22', 'Support your hands or feet on a ledge.', 'Therapeutic Protocol: Ledge Support', 'Utilize a window ledge or wall protrusion to provide stable height for hand or foot placement.', '2026-04-11 08:23:58.429201+00'),
	('belt_or_strap', 'Belt or Strap', 'âž°', '#8E4D1E', 'Use a belt or a strap', 'Therapeutic Protocol: Using a Strap or Belt', 'Using a yoga belt acts as an extension of your limbs, allowing you to maintain proper alignment and safely increase your reach without straining or overstretching.', '2026-04-11 08:27:30.249758+00'),
	('stool_or_table', 'Stool or Table', 'ðŸ”²', '#34495e', 'Use a stool or table for torso support.', 'Therapeutic Protocol: Elevated Support', 'Utilize a stable stool or table to bring the floor to you. This provides a high, firm base for restorative poses.<br><strong>Adjustment:</strong> Place two bolsters on the surface to fully support the length of the torso and head.<br><small><em>Benefit: Relieves spinal pressure and calms the nervous system by allowing the heart and head to rest at hip height.</em></small>', '2026-04-12 01:33:46.071989+00'),
	('bolster', 'Bolster', 'ðŸ’Š', '#2980b9', 'Position a bolster for firm support.', 'Therapeutic Protocol: Bolster Support', 'Bolsters provide firm, stable elevation to expand the chest or support the limbs. Use one or more to create a cushioned surface.<br><strong>Substitution:</strong> If a bolster is unavailable, use 2-3 firmly folded blankets or a tightly rolled large towel to achieve similar height.<br><small><em>Benefit: Facilitates deep relaxation by fully supporting the body''s weight, allowing the muscles to release.</em></small>', '2026-04-12 02:21:45.844116+00');
