	('II', '044', 'Supta Baddha Konasana (on the floor)', NULL, 'Sit facing a wall with the soles of the feet together and knees apart. Curl the toes back and press them against the wall.
INSERT INTO "public"."yoga_source_sections" ("id", "source_key", "section_number", "section_code", "section_title", "section_summary", "created_at") VALUES
	(1, 'yoga_gem_for_women', 1, 'I', 'Standing poses', 'Basic training for beginners; develops elasticity, stamina and physical stability.', '2026-05-03 04:37:48.619748+00'),
	(2, 'yoga_gem_for_women', 2, 'II', 'Forward bends', 'Extends the posterior body; develops physical and mental pliability.', '2026-05-03 04:37:48.619748+00'),
	(3, 'yoga_gem_for_women', 3, 'III', 'Sitting upright and supine extending positions', 'Prepares the body and mind for pranayama.', '2026-05-03 04:37:48.619748+00'),
	(4, 'yoga_gem_for_women', 4, 'IV', 'Inverted postures', 'Supports recovery from strain and stress; develops vitality, mental balance and emotional stability.', '2026-05-03 04:37:48.619748+00'),
	(5, 'yoga_gem_for_women', 5, 'V', 'Abdominal, pelvic and lumbar work', 'Tones and massages abdominal organs; strengthens pelvic and lumbar areas.', '2026-05-03 04:37:48.619748+00'),
	(6, 'yoga_gem_for_women', 6, 'VI', 'Lateral stretches and twists', 'Works the spine and internal organs; develops tranquillity.', '2026-05-03 04:37:48.619748+00'),
	(7, 'yoga_gem_for_women', 7, 'VII', 'Backbends', 'Invigorating and enlivening; stretches the anterior spine.', '2026-05-03 04:37:48.619748+00'),
	(8, 'yoga_gem_for_women', 8, 'VIII', 'Yoga Kurunta / rope work', 'Uses ropes for accuracy, agility and balance; useful for stiffness, age or fear.', '2026-05-03 04:37:48.619748+00'),
	(9, 'yoga_gem_for_women', 9, 'IX', 'Pregnancy practice', 'Asanas and pranayamas for expectant mothers.', '2026-05-03 04:37:48.619748+00'),
	(10, 'yoga_gem_for_women', 10, 'X', 'Advanced asanas', 'Advanced and complicated asanas for serious students.', '2026-05-03 04:37:48.619748+00'),
	(11, 'yoga_gem_for_women', 11, 'XI', 'Mudras and Savasana', 'Mudras and Savasana.', '2026-05-03 04:37:48.619748+00'),
	(12, 'yoga_gem_for_women', 12, 'XII', 'Pranayama and Dhyana', 'Pranayama and meditation.', '2026-05-03 04:37:48.619748+00');
